import React from 'react';

function BookList({ books, onBookSelect, onShowAddForm }) {
  const totalBooks = books.length;
  const averageRating = books.length > 0 
    ? (books.reduce((sum, book) => sum + book.rating, 0) / books.length).toFixed(1)
    : 0;
  const totalReviews = books.reduce((sum, book) => sum + book.reviews.length, 0);

  return (
    <div className="animate-fade-in">
      {/* Modern Header */}
      <header className="text-center mb-12">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-primary rounded-2xl mb-6 shadow-lg">
          <span className="text-2xl">📚</span>
        </div>
        <h1 className="text-4xl md:text-5xl font-bold mb-4 text-gradient-primary">
          Modern Library
        </h1>
        <p className="text-lg text-secondary max-w-2xl mx-auto">
          Discover and manage your personal book collection
        </p>
      </header>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
        <div className="card card-body text-center animate-fade-in-up animate-delay-100">
          <div className="text-3xl font-bold text-primary mb-2">{totalBooks}</div>
          <div className="text-secondary text-sm font-medium uppercase tracking-wide">Books</div>
        </div>
        <div className="card card-body text-center animate-fade-in-up animate-delay-200">
          <div className="text-3xl font-bold text-primary mb-2">{averageRating}★</div>
          <div className="text-secondary text-sm font-medium uppercase tracking-wide">Avg Rating</div>
        </div>
        <div className="card card-body text-center animate-fade-in-up animate-delay-300">
          <div className="text-3xl font-bold text-primary mb-2">{totalReviews}</div>
          <div className="text-secondary text-sm font-medium uppercase tracking-wide">Reviews</div>
        </div>
      </div>

      {/* Action Button */}
      <div className="text-center mb-12">
        <button
          onClick={onShowAddForm}
          className="btn btn-primary btn-lg animate-fade-in-up animate-delay-500"
        >
          <svg className="icon-sm mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
          </svg>
          Add New Book
        </button>
      </div>

      {/* Books Grid */}
      {books.length === 0 ? (
        <div className="text-center py-20 animate-fade-in-up">
          <div className="text-6xl mb-6 opacity-50">📖</div>
          <h3 className="text-2xl font-bold text-primary mb-4">Your library is empty</h3>
          <p className="text-secondary text-lg mb-8">Add your first book to get started</p>
          <button
            onClick={onShowAddForm}
            className="btn btn-primary"
          >
            Add Your First Book
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6">
          {books.map((book, index) => (
            <div
              key={book.id}
              className="group cursor-pointer animate-fade-in-up"
              style={{ animationDelay: `${index * 100}ms` }}
              onClick={() => onBookSelect(book)}
            >
              <div className="card h-full hover:shadow-lg transition-all duration-300 hover:-translate-y-1">
                <div className="card-body">
                  {/* Book Title */}
                  <h3 className="text-xl font-bold text-primary mb-2 line-clamp-2 group-hover:text-primary transition-colors">
                    {book.title}
                  </h3>

                  {/* Author */}
                  <p className="text-secondary mb-4">
                    by {book.author}
                  </p>

                  {/* Rating */}
                  <div className="flex items-center gap-2 mb-4">
                    <div className="flex items-center">
                      {[...Array(5)].map((_, i) => (
                        <span
                          key={i}
                          className={`text-lg ${
                            i < Math.floor(book.rating) ? 'text-warning' : 'text-muted'
                          }`}
                        >
                          ★
                        </span>
                      ))}
                    </div>
                    <span className="text-sm font-medium text-primary">
                      {book.rating.toFixed(1)}
                    </span>
                  </div>

                  {/* Review Count */}
                  <div className="text-sm text-muted mb-4">
                    {book.reviews.length} review{book.reviews.length !== 1 ? 's' : ''}
                  </div>

                  {/* Read More Indicator */}
                  <div className="flex items-center text-primary opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                    <span className="text-sm font-medium">View Details</span>
                    <svg className="icon-sm ml-2 transform group-hover:translate-x-1 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                    </svg>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default BookList;
